module model_compare_counter_core #(
    parameter integer COUNT_WIDTH = 8,
    parameter integer STEP_WIDTH  = 4
) (
    input  logic                    clk,
    input  logic                    rst_n,
    input  logic                    enable,
    input  logic                    clear,
    input  logic [STEP_WIDTH-1:0]   step,
    output logic [COUNT_WIDTH-1:0]  count,
    output logic                    wrapped,
    output logic                    valid
);

    localparam [COUNT_WIDTH-1:0] COUNT_ZERO = {COUNT_WIDTH{1'b0}};

    // Architectural state variables from function_model.state_variables
    logic [COUNT_WIDTH-1:0] count_q;
    logic                   wrapped_q;
    logic                   valid_q;

    logic [COUNT_WIDTH-1:0] out_count;
    logic                   out_wrapped;
    logic                   out_valid;

    logic [COUNT_WIDTH-1:0] next_count_q;
    logic                   next_wrapped_q;
    logic                   next_valid_q;

    // FM_UPDATE arithmetic: zero-extend step and detect overflow carry-out.
    logic [COUNT_WIDTH:0] add_sum_w;

    // Acceptance under cycle_model rules: no backpressure, sampled each cycle.
    logic fm_clear_accept;
    logic fm_update_accept;
    logic fm_idle_accept;

    assign add_sum_w = {1'b0, count_q} + {{(COUNT_WIDTH-STEP_WIDTH){1'b0}}, step};

    assign fm_clear_accept  = (clear == 1'b1);
    assign fm_update_accept = (clear == 1'b0) && (enable == 1'b1);
    assign fm_idle_accept   = (clear == 1'b0) && (enable == 1'b0);

    // Mirrored SSOT output rule observables (out_count/out_wrapped/out_valid).
    assign out_count   = count_q;
    assign out_wrapped = wrapped_q;
    assign out_valid   = valid_q;

    assign count   = out_count;
    assign wrapped = out_wrapped;
    assign valid   = out_valid;

    // Next-state logic for FM_CLEAR / FM_UPDATE / FM_IDLE.
    always @(*) begin
        next_count_q   = count_q;
        next_wrapped_q = 1'b0;
        next_valid_q   = 1'b0;

        if (fm_clear_accept) begin
            // FM_CLEAR: clear has priority over enable and forces zeros.
            next_count_q   = COUNT_ZERO;
            next_wrapped_q = 1'b0;
            next_valid_q   = 1'b0;
        end else if (fm_update_accept) begin
            // FM_UPDATE: modulo update and overflow pulse in same commit edge.
            next_count_q   = add_sum_w[COUNT_WIDTH-1:0];
            next_wrapped_q = add_sum_w[COUNT_WIDTH];
            next_valid_q   = 1'b1;
        end else if (fm_idle_accept) begin
            // FM_IDLE: hold count_q and deassert one-cycle pulse outputs.
            next_count_q   = count_q;
            next_wrapped_q = 1'b0;
            next_valid_q   = 1'b0;
        end else begin
            // Defensive default for unknown combinations; preserves FM_IDLE behavior.
            next_count_q   = count_q;
            next_wrapped_q = 1'b0;
            next_valid_q   = 1'b0;
        end
    end

    // Latency-1 commit: inputs sampled at edge N, outputs visible after edge N.
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            count_q   <= COUNT_ZERO;
            wrapped_q <= 1'b0;
            valid_q   <= 1'b0;
        end else begin
            count_q   <= next_count_q;
            wrapped_q <= next_wrapped_q;
            valid_q   <= next_valid_q;
        end
    end

endmodule

